  ('optometrist-moex-03572', 'optometrist', 'optometrist-moex-106-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '由一+10.0 D接目鏡及一+4.0 D接物鏡組成之天文望遠鏡，則此天文望遠鏡的管長約為多少cm？', '["10", "15", "30", "35"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "c0506c210b76", "answer_pdf_sha1": "f66fae525935", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
